import{c as t,Q as e,j as o,m as s}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"Nano Banana2 Pro绘图教程","description":"","frontmatter":{},"headers":[],"relativePath":"paint/Banana.md","filePath":"paint/Banana.md","lastUpdated":1779875536000}'),i={name:"paint/Banana.md"};function n(c,a,p,r,l,d){return e(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="nano-banana2-pro绘图教程" tabindex="-1">Nano Banana2 Pro绘图教程 <a class="header-anchor" href="#nano-banana2-pro绘图教程" aria-label="Permalink to &quot;Nano Banana2 Pro绘图教程&quot;">​</a></h1><hr><h2 id="使用cherry-studio绘图" tabindex="-1">使用Cherry Studio绘图 <a class="header-anchor" href="#使用cherry-studio绘图" aria-label="Permalink to &quot;使用Cherry Studio绘图&quot;">​</a></h2><ol><li>参照 <a href="/register/4-token.html">创建密钥分组</a> 一章的教程，你需要创建<strong>密钥分组</strong> 为 <code>gemini</code> 的令牌。在创建好令牌后，点击图中复制按钮，将令牌复制到剪切板</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/banana/01.webp" alt=""></p><ol start="2"><li><p>访问 <a href="https://www.cherry-ai.com/" target="_blank" rel="noreferrer">Cherry Studio</a> 官网进行下载</p></li><li><p>打开 Cherry Studio软件，点击右上角设置按钮</p></li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/banana/02.webp" alt=""></p><ol start="4"><li>选择左侧 <code>模型服务</code> ，点击最下面的 <code>添加</code> 按钮</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/banana/03.webp" alt=""></p><ol start="5"><li>在添加提供商窗口按照如下图，写入提供商名称与提供商类型</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/banana/04.webp" alt=""></p><ol start="6"><li>在左侧列表中找到刚添加的 <code>Packyapi</code> 分组，API密钥部分填入第一步创建后复制的 <code>gemini</code> 分组的API密钥，API地址填写 <code>https://www.suirenai.com</code></li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/banana/05.webp" alt=""></p><ol start="7"><li>点击下方的 <code>管理</code> 按钮，在弹出的模型列表中选择我们的绘图模型，Packy已经对一些常用比例与分辨率模型做了优化适配，我们可以如下图直接选择</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/banana/06.webp" alt=""></p><ol start="8"><li>添加好后如下图所示</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/banana/07.webp" alt=""></p><ol start="9"><li>点击左上角的 <code>首页</code> 按钮回到主页，点击目前你所使用助手的右侧设置按钮。在 <code>模型设置</code> 一栏找到 <code>流式输出</code> 一项，请务必关闭，然后点击右上角关闭窗口</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/banana/08.webp" alt=""><img src="https://docs.packyapi.com/assets/image/Paint/banana/09.webp" alt=""></p><ol start="10"><li>点击上方模型设置处，选择我们刚才创建分组的绘图模型</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/banana/10.webp" alt=""></p><ol start="11"><li>尽情发挥你的想象吧~</li></ol><p><img src="https://docs.packyapi.com/assets/image/Paint/banana/11.webp" alt=""></p>',23)])])}const b=t(i,[["render",n]]);export{h as __pageData,b as default};
